SELECT count(*) FROM name, aka_name, cast_info, title, role_type, movie_info, kind_type, char_name, info_type WHERE aka_name.person_id = name.id AND cast_info.person_id = name.id AND cast_info.movie_id = title.id AND cast_info.role_id = role_type.id AND movie_info.movie_id = title.id AND title.kind_id = kind_type.id AND cast_info.person_role_id = char_name.id AND movie_info.info_type_id = info_type.id;